const messaging = $('Webhook').first().json.body.entry[0].messaging[0];
if (!messaging) {
  return [];
}

const isEcho = messaging?.message?.is_echo === true;
const appId = messaging?.message?.app_id;
const metadata = messaging?.message?.metadata;


if (isEcho && appId) {
  console.log("Skipping bot echo message");
  return [];
}

if (isEcho && !appId) {
  console.log("Processing human agent response");
  return [$input.item];
}

const hasText = messaging?.message?.text;
const hasAttachments = messaging?.message?.attachments?.length > 0;
const isDelivery = !!messaging?.delivery;
const isRead = !!messaging?.read;
const isPostback = !!messaging?.postback;

// Skip if it's a delivery/read receipt or postback, but allow text OR attachments
if (isDelivery || isRead || isPostback) {
  return [];
}

// Must have either text or attachments
if (!hasText && !hasAttachments) {
  return [];
}

const timestamp = messaging?.timestamp;
if (!timestamp) {
  return [];
}

const messageTime = timestamp;
const now = Date.now();
const fiveMinutesAgo = now - (5 * 60 * 1000);

if (messageTime < fiveMinutesAgo) {
  console.log(`Skipping old message from ${Math.floor((now - messageTime) / 1000 / 60)} minutes ago`);
  return [];
}

if (hasText) {
  console.log(`Processing valid message: "${messaging.message.text}"`);
} else if (hasAttachments) {
  console.log(`Processing message with ${hasAttachments.length} attachment(s)`);
}

return [$input.item];

// Get raw AI or dynamic text
const rawText = $json.output || $input.first().json.message.content || "";
const sender = $('Webhook').first().json.body.entry[0].messaging[0].sender.id || "";
const reciever = $('Webhook').first().json.body.entry[0].messaging[0].recipient.id || "";

// Sanitize text for JSON / messaging APIs
const sanitizedText = rawText
  .replace(/\\/g, "\\\\")        // Escape backslashes
  .replace(/"/g, '\\"')         // Escape double quotes
  .replace(/\r?\n|\r/g, "\\n")  // Convert line breaks to \n
  .replace(/\t/g, " ")          // Replace tabs with space
  .trim();

// Return clean output
return [
  {
    json: {
      sanitizedOutput: sanitizedText,
      sender : sender,
      receiver : reciever
    }
  }
];

const text = $input.first().json.content
  .replace(/\n{5,}/g, '\n\n') // reduce multiple blank lines to a single blank line
  .trim();

return [{ json: { instruction: text } }];

const items = $input.all();

const instruction = items.find(i => i.json?.instruction)?.json?.instruction;
// const pricelist = items.find(i => i.json?.text)?.json?.text;

const webhook = $('Webhook').first()?.json?.body;
const message = webhook?.entry?.[0]?.messaging?.[0]?.message?.text;
const senderID = webhook?.entry?.[0]?.messaging?.[0]?.sender?.id;
const classifierMemory = webhook?.entry?.[0]?.messaging?.[0]?.sender?.id+ '-response';

return [{
  json: {
    message,
    instruction,
    senderID,
    classifierMemory,
  }
}];

